-- ملء محتوى عنقود "العلاقات الدولية في الإسلام" (alaqat-dawliyya) — أربعة
-- تصنيفات فرعية، كلها draft (استنفاد كامل للعنقود): السلم والعهود
-- والأمان والوفاء بالعقود، حقوق غير المسلمين والجوار والسفراء،
-- النزاعات والأسرى والقانون الدولي الإنساني، الدعوة والحوار
-- والاتفاقيات المعاصرة.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس qada-dawa-ithbat/tarikh-tashri
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الفقه الإسلامي وأدلته لوهبة الزحيلي (السلم والعهود
-- والأمان؛ والدعوة والحوار والاتفاقيات المعاصرة)، أحكام أهل الذمة لابن
-- القيم الجوزية (حقوق غير المسلمين والجوار والسفراء)، آثار الحرب في
-- الفقه الإسلامي لوهبة الزحيلي (الأسرى وضوابط النزاع المسلح).
-- أربعة أحاديث استُشهد بها، تحقَّقت حرفياً عبر WebSearch قبل الإدراج:
-- "ذمة المسلمين واحدة يسعى بها أدناهم..." (متفق عليه، رواه البخاري
-- 3172، عن علي بن أبي طالب)، "من قتل معاهدًا لم يرح رائحة الجنة..."
-- (رواه البخاري 3166 منفردًا، عن عبد الله بن عمرو)، نهي النبي صلى الله
-- عليه وسلم عن قتل النساء والصبيان (متفق عليه، رواه البخاري 3015
-- ومسلم 1744، عن ابن عمر)، كتاب النبي صلى الله عليه وسلم إلى هرقل
-- "أسلم تسلم يؤتك الله أجرك مرتين" (متفق عليه، رواه البخاري 7 ومسلم
-- 1773، عن ابن عباس).
-- أربع آيات تحقَّقت حرفياً محلياً من
-- artifacts/majalis/public/data/quran عبر حقل numberInSurah: المائدة 1
-- (الوفاء بالعقود)، الممتحنة 8 (البر والقسط مع غير المحاربين)، محمد 4
-- (المنّ أو الفداء في الأسرى)، النحل 125 (الدعوة بالحكمة).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) السلم والعهود والأمان والوفاء بالعقود
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ff2f777e-995c-48eb-8c4a-6fbffb7ae268' AND title='السلم والعهود والأمان في العلاقات الدولية الإسلامية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('السلم والعهود والأمان في العلاقات الدولية الإسلامية', 'تعريف موجز بأصل السلم في العلاقات الدولية الإسلامية ومنزلة الوفاء بالعهود والعقود وعقد الأمان', 'ff2f777e-995c-48eb-8c4a-6fbffb7ae268', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'السلم أصل العلاقة، والعهد والأمان أداتا تنظيمها', 'الأصل في العلاقة بين المسلمين وغيرهم من الأمم والدول هو السلم لا الحرب، وهذا ما قرره جمهور المحققين من الفقهاء المعاصرين خلافًا لما اشتهر عند بعض المتقدمين من جعل الحرب هي الأصل والسلم استثناءً؛ فالقتال في الإسلام إنما شُرع لدفع عدوان أو حماية دعوة لا لذاته، ويؤكد هذا المعنى ميل النبي صلى الله عليه وسلم للصلح كلما أمكن، كما في صلح الحديبية. ومن أهم أدوات تنظيم العلاقات الدولية في الفقه الإسلامي: العهد (المعاهدة)، وهو اتفاق ملزم بين المسلمين وغيرهم يجب الوفاء به ما لم يُنقض بإعلان صريح مسبق؛ والأمان (عقد الأمان)، وهو تعهد بحماية شخص أو جماعة من غير المسلمين من القتال والتعرض، ويصح منحه من أي مسلم مكلف ولو كان آحاد الناس لا سلطة له، ويكون ملزمًا لعموم المسلمين لا لمانحه وحده، تحقيقًا لمبدأ وحدة الذمة الذي فصّله الفقهاء في باب الجزية والأمان، كما بيّن وهبة الزحيلي في مباحث العلاقات الدولية من موسوعته "الفقه الإسلامي وأدلته".', 1),
    (v_lesson, 'examples', 'الوفاء بالعقود أصل قرآني عام، ووحدة ذمة المسلمين أصل نبوي في الأمان', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ﴾ (المائدة: 1)، افتتح الله بها هذه السورة أصلًا جامعًا يشمل كل عقد وعهد بين المسلمين وغيرهم، فضلًا عن العقود الداخلية بينهم. وعن علي بن أبي طالب رضي الله عنه، فيما رواه من أن النبي صلى الله عليه وسلم قال: «ذمة المسلمين واحدة يسعى بها أدناهم، فمن أخفر مسلمًا فعليه لعنة الله والملائكة والناس أجمعين، لا يقبل الله منه صرفًا ولا عدلًا» (متفق عليه، رواه البخاري 3172)، وهذا الحديث أصل عظيم يقرر أن عقد الأمان الذي يمنحه أدنى المسلمين رتبةً ملزم لعموم الأمة، لا يجوز لأحد نقضه أو الغدر به.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — وهبة الزحيلي', 1);
  END IF;

  -- 2) حقوق غير المسلمين والجوار والسفراء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='41f51113-8493-4409-a700-b813b312caa8' AND title='حقوق غير المسلمين المعاهَدين وحرمة الجوار والسفراء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حقوق غير المسلمين المعاهَدين وحرمة الجوار والسفراء', 'تعريف موجز بحقوق غير المسلمين المعاهَدين والمستأمَنين وحرمة الجار والسفير في الفقه الإسلامي', '41f51113-8493-4409-a700-b813b312caa8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حرمة الدم والمال والعرض، وحصانة الجار والسفير', 'غير المسلمين المرتبطين بعقد ذمة دائم أو عهد مؤقت (المعاهَدون والمستأمَنون) لهم في الفقه الإسلامي حقوق واجبة الرعاية، فصّلها ابن القيم الجوزية تفصيلًا واسعًا في كتابه "أحكام أهل الذمة": حرمة الدم والمال والعرض، فلا يجوز الاعتداء عليهم أو أخذ شيء من أموالهم بغير حق؛ وحرية ممارسة شعائرهم الدينية الخاصة ضمن الضوابط المتفق عليها في عقد الذمة؛ والعدل في المعاملة وعدم تكليفهم فوق طاقتهم. وقد بالغ الفقهاء في التحذير من ظلمهم حتى عدّوا الاعتداء على المعاهَد من كبائر الذنوب الموجبة للوعيد الشديد. ويلحق بذلك حرمة الجار ولو كان غير مسلم، فحسن الجوار من مكارم الأخلاق التي حث عليها الشرع عمومًا. أما السفراء والرسل، فقد استقر عرف الفقهاء وتطبيق النبي صلى الله عليه وسلم على حرمة التعرض لهم بالأذى ولو كانوا مرسَلين من جهة معادية، لأن مهمتهم التبليغ لا القتال، وهو أصل مبكر لما عُرف لاحقًا في القانون الدولي بالحصانة الدبلوماسية.', 1),
    (v_lesson, 'examples', 'البر والقسط مع غير المحاربين، وحرمة قتل المعاهَد', 'قال تعالى: ﴿لَا يَنْهَاكُمُ اللَّهُ عَنِ الَّذِينَ لَمْ يُقَاتِلُوكُمْ فِي الدِّينِ وَلَمْ يُخْرِجُوكُم مِّن دِيَارِكُمْ أَن تَبَرُّوهُمْ وَتُقْسِطُوا إِلَيْهِمْ ۚ إِنَّ اللَّهَ يُحِبُّ الْمُقْسِطِينَ﴾ (الممتحنة: 8)، وهي أصل قرآني صريح في وجوب البر والعدل مع غير المسلمين الذين لم يقاتلوا المسلمين ولم يخرجوهم من ديارهم. وعن عبد الله بن عمرو رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «من قتل معاهَدًا لم يرح رائحة الجنة، وإن ريحها توجد من مسيرة أربعين عامًا» (رواه البخاري 3166)، وهذا وعيد شديد على من اعتدى بالقتل على من له عهد أو ذمة مع المسلمين، تأكيدًا لعظم حرمة دمه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أحكام أهل الذمة — ابن القيم الجوزية', 1);
  END IF;

  -- 3) النزاعات والأسرى والقانون الدولي الإنساني
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c74e980f-64df-4fca-aaa5-fdae15c6384d' AND title='أحكام الأسرى وضوابط النزاع المسلح في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام الأسرى وضوابط النزاع المسلح في الفقه الإسلامي', 'تعريف موجز بأحكام معاملة أسرى الحرب وضوابط سلوك القتال التي تمثل أصول القانون الدولي الإنساني في الفقه الإسلامي', 'c74e980f-64df-4fca-aaa5-fdae15c6384d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التمييز بين المقاتلين وغيرهم، والمنّ أو الفداء في الأسرى', 'وضع الفقه الإسلامي ضوابط صارمة لسلوك القتال تمثل جذورًا مبكرة لما يُعرف اليوم بالقانون الدولي الإنساني، فصّلها الفقهاء في أبواب السير والجهاد، ومن أبرزها ما استقصاه وهبة الزحيلي في كتابه المتخصص "آثار الحرب في الفقه الإسلامي": تحريم قتل من لا يقاتل من النساء والصبيان والشيوخ العاجزين والرهبان المنقطعين للعبادة، لأن القتال إنما شُرع لدفع المقاتِلين لا للانتقام من غير المحاربين؛ وتحريم المُثلة والتعذيب وتخريب ما لا ضرورة لتخريبه من العمران والزرع إلا لضرورة قتالية بيّنة. وأما أسرى الحرب فقد خيّر القرآن ولي الأمر فيهم بين المنّ عليهم بإطلاقهم مجانًا أو مفاداتهم بمال أو بأسرى مسلمين، مراعاةً للمصلحة العامة، مع وجوب الإحسان إليهم أثناء الأسر بالطعام والمأوى وعدم إهانتهم، امتثالًا لهدي النبي صلى الله عليه وسلم في معاملة أسرى بدر.', 1),
    (v_lesson, 'examples', 'المنّ أو الفداء في الأسرى، وحرمة قتل غير المقاتلين', 'قال تعالى: ﴿فَإِذَا لَقِيتُمُ الَّذِينَ كَفَرُوا فَضَرْبَ الرِّقَابِ حَتَّىٰ إِذَا أَثْخَنتُمُوهُمْ فَشُدُّوا الْوَثَاقَ فَإِمَّا مَنًّا بَعْدُ وَإِمَّا فِدَاءً حَتَّىٰ تَضَعَ الْحَرْبُ أَوْزَارَهَا﴾ (محمد: 4)، وهي الأصل القرآني في التخيير بين المنّ والفداء في أسرى الحرب بعد انتهاء القتال الفعلي. وعن عبد الله بن عمر رضي الله عنهما: أن امرأة وُجدت مقتولة في بعض مغازي النبي صلى الله عليه وسلم، فأنكر رسول الله صلى الله عليه وسلم ذلك ونهى عن قتل النساء والصبيان (متفق عليه، رواه البخاري 3015 ومسلم 1744)، وهذا الحديث أصل صريح في تحريم استهداف غير المقاتلين في النزاع المسلح، وهو ما يقابل اليوم مبدأ التمييز بين المقاتلين والمدنيين في القانون الدولي الإنساني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'آثار الحرب في الفقه الإسلامي — وهبة الزحيلي', 1);
  END IF;

  -- 4) الدعوة والحوار والاتفاقيات المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6b3ef519-14d0-47a3-8a61-cbca70a03f03' AND title='الدعوة بالحكمة والحوار وصياغة الاتفاقيات الدولية المعاصرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الدعوة بالحكمة والحوار وصياغة الاتفاقيات الدولية المعاصرة', 'تعريف موجز بمنهج الدعوة والحوار بالحكمة وامتداد أصل المراسلات النبوية إلى صياغة الاتفاقيات الدولية المعاصرة', '6b3ef519-14d0-47a3-8a61-cbca70a03f03', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الحكمة أصل الدعوة، والمراسلات النبوية أصل الدبلوماسية', 'الأصل المنهجي للدعوة إلى الإسلام والحوار مع الآخر في الفقه الإسلامي هو الحكمة والموعظة الحسنة والمجادلة بالتي هي أحسن، لا الإكراه أو الإلزام، وهو منهج عام يشمل التبليغ الفردي والمخاطبات الرسمية بين الدول على حد سواء. وقد أرسى النبي صلى الله عليه وسلم أصل المخاطبات الدبلوماسية بين الدول حين بعث برسائل رسمية إلى ملوك عصره (هرقل عظيم الروم، والمقوقس عظيم مصر، والنجاشي ملك الحبشة، وكسرى ملك الفرس) يدعوهم فيها إلى الإسلام بأسلوب الحكمة والاحترام المتبادل، دون تهديد بالقتال المباشر، وهو ما يمثل أحد أقدم النماذج المسجَّلة للمراسلات الدبلوماسية الرسمية بين الدول في التاريخ الإسلامي. وعلى هذا الأصل (الحوار بالحكمة، والالتزام بالعهود المكتوبة) بنى الفقه المعاصر جواز الدخول في المعاهدات والاتفاقيات الدولية المعاصرة (كمواثيق الأمم المتحدة والاتفاقيات الثنائية والجماعية)، ما لم تتضمن نصًا يخالف قطعيًا من الشريعة، كما بحثه وهبة الزحيلي في مباحث المعاهدات الدولية من موسوعته "الفقه الإسلامي وأدلته".', 1),
    (v_lesson, 'examples', 'الدعوة بالحكمة أصل قرآني، ورسائل النبي للملوك تأسيس للمراسلات الدبلوماسية', 'قال تعالى: ﴿ادْعُ إِلَىٰ سَبِيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ وَجَادِلْهُم بِالَّتِي هِيَ أَحْسَنُ﴾ (النحل: 125)، وهي الأصل القرآني الجامع لمنهج الدعوة والحوار بالحكمة لا بالإكراه. ومن تطبيقات هذا الأصل في المراسلات الرسمية بين الدول: كتاب النبي صلى الله عليه وسلم إلى هرقل عظيم الروم، وفيه: «من محمد عبد الله ورسوله إلى هرقل عظيم الروم... سلام على من اتبع الهدى، أما بعد، فإني أدعوك بدعاية الإسلام، أسلم تسلم، يؤتك الله أجرك مرتين» (متفق عليه، رواه البخاري 7 ومسلم 1773)، وهو نموذج مبكر لصياغة المخاطبات الرسمية بين رأسي دولتين بأسلوب الحكمة والاحترام المتبادل.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — وهبة الزحيلي', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    'ff2f777e-995c-48eb-8c4a-6fbffb7ae268', '41f51113-8493-4409-a700-b813b312caa8',
    'c74e980f-64df-4fca-aaa5-fdae15c6384d', '6b3ef519-14d0-47a3-8a61-cbca70a03f03'
  );
END $$;
